And finally, the JavaScript to bring it all together:

```javascript
// app.js - Dashboard logic and chart initialization

let charts = {};

// Format currency
function formatCurrency(amount) {
    return new Intl.NumberFormat('en-US', {
        style: 'currency',
        currency: 'USD',
        minimumFractionDigits: 0,
        maximumFractionDigits: 0
    }).format(amount);
}

// Calculate percentage change
function calculateChange(current, previous) {
    const change = ((current - previous) / previous) * 100;
    return change.toFixed(1);
}

// Update metric cards
function updateMetrics() {
    const { revenue, orders, visitors, previousRevenue, previousOrders, previousVisitors } = sampleData.currentPeriod;

    const avgOrderValue = revenue / orders;
    const previousAvgOrderValue = previousRevenue / previousOrders;
    const conversionRate = (orders / visitors) * 100;
    const previousConversionRate = (previousOrders / previousVisitors) * 100;

    // Total Revenue
    document.getElementById('totalRevenue').textContent = formatCurrency(revenue);
    const revenueChange = calculateChange(revenue, previousRevenue);
    const revenueChangeEl = document.getElementById('revenueChange');
    revenueChangeEl.textContent = `${revenueChange > 0 ? '+' : ''}${revenueChange}%`;
    revenueChangeEl.className = `metric-change ${revenueChange >= 0 ? 'positive' : 'negative'}`;

    // Total Orders
    document.getElementById('totalOrders').textContent = orders.toLocaleString();
    const ordersChange = calculateChange(orders, previousOrders);
    const ordersChangeEl = document.getElementById('ordersChange');
    ordersChangeEl.textContent = `${ordersChange > 0 ? '+' : ''}${ordersChange}%`;
    ordersChangeEl.className = `metric-change ${ordersChange >= 0 ? 'positive' : 'negative'}`;

    // Average Order Value
    document.getElementById('avgOrderValue').textContent = formatCurrency(avgOrderValue);
    const aovChange = calculateChange(avgOrderValue, previousAvgOrderValue);
    const aovChangeEl = document.getElementById('aovChange');
    aovChangeEl.textContent = `${aovChange > 0 ? '+' : ''}${aovChange}%`;
    aovChangeEl.className = `metric-change ${aovChange >= 0 ? 'positive' : 'negative'}`;

    // Conversion Rate
    document.getElementById('conversionRate').textContent = `${conversionRate.toFixed(1)}%`;
    const conversionChange = calculateChange(conversionRate, previousConversionRate);
    const conversionChangeEl = document.getElementById('conversionChange');
    conversionChangeEl.textContent = `${conversionChange > 0 ? '+' : ''}${conversionChange}%`;
    conversionChangeEl.className = `metric-change ${conversionChange >= 0 ? 'positive' : 'negative'}`;
}

// Initialize Revenue Trend Chart
function initRevenueChart() {
    const ctx = document.getElementById('revenueChart').getContext('2d');

    charts.revenue = new Chart(ctx, {
        type: 'line',
        data: {
            labels: sampleData.revenueByDay.map(d => new Date(d.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })),
            datasets: [{
                label: 'Daily Revenue',
                data: sampleData.revenueByDay.map(d => d.revenue),
                borderColor: '#3498db',
                backgroundColor: 'rgba(52, 152, 219, 0.1)',
                tension: 0.4,
                fill: true
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: true,
            plugins: {
                legend: {
                    display: false
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    ticks: {
                        callback: function(value) {
                            return '$' + value.toLocaleString();
                        }
                    }
                }
            }
        }
    });
}

// Initialize Category Chart
function initCategoryChart() {
    const ctx = document.getElementById('categoryChart').getContext('2d');

    charts.category = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: sampleData.salesByCategory.map(c => c.category),
            datasets: [{
                data: sampleData.salesByCategory.map(c => c.sales),
                backgroundColor: [
                    '#3498db',
                    '#2ecc71',
                    '#f39c12',
                    '#e74c3c',
                    '#9b59b6'
                ]
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: true,
            plugins: {
                legend: {
                    position: 'right'
                }
            }
        }
    });
}

// Initialize Monthly Comparison Chart
function initMonthlyChart() {
    const ctx = document.getElementById('monthlyChart').getContext('2d');

    charts.monthly = new Chart(ctx, {
        type: 'bar',
        data: {
            labels: sampleData.monthlyComparison.map(m => m.month),
            datasets: [{
                label: 'Monthly Revenue',
                data: sampleData.monthlyComparison.map(m => m.revenue),
                backgroundColor: '#2ecc71'
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: true,
            plugins: {
                legend: {
                    display: false
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    ticks: {
                        callback: function(value) {
                            return '$' + value.toLocaleString();
                        }
                    }
                }
            }
        }
    });
}

// Initialize Top Products Chart
function initProductsChart() {
    const ctx = document.getElementById('productsChart').getContext('2d');

    charts.products = new Chart(ctx, {
        type: 'bar',
        data: {
            labels: sampleData.topProducts.map(p => p.name),
            datasets: [{
                label: 'Revenue',
                data: sampleData.topProducts.map(p => p.revenue),
                backgroundColor: '#9b59b6'
            }]
        },
        options: {
            indexAxis: 'y',
            responsive: true,
            maintainAspectRatio: true,
            plugins: {
                legend: {
                    display: false
                }
            },
            scales: {
                x: {
                    beginAtZero: true,
                    ticks: {
                        callback: function(value) {
                            return '$' + value.toLocaleString();
                        }
                    }
                }
            }
        }
    });
}

// Populate transactions table
function populateTransactionsTable() {
    const tbody = document.getElementById('transactionsBody');
    tbody.innerHTML = '';

    sampleData.recentTransactions.forEach(transaction => {
        const row = tbody.insertRow();
        row.innerHTML = `
            <td>${transaction.id}</td>
            <td>${transaction.date}</td>
            <td>${transaction.customer}</td>
            <td>${transaction.product}</td>
            <td>${formatCurrency(transaction.amount)}</td>
            <td><span class="status ${transaction.status}">${transaction.status}</span></td>
        `;
    });
}

// Initialize dashboard
function initDashboard() {
    updateMetrics();
    initRevenueChart();
    initCategoryChart();
    initMonthlyChart();
    initProductsChart();
    populateTransactionsTable();
}

// Period selector handler
document.getElementById('periodSelect').addEventListener('change', function(e) {
    // In a real application, this would fetch new data based on the selected period
    console.log('Period changed to:', e.target.value);
});

// Initialize on page load
document.addEventListener('DOMContentLoaded', initDashboard);
```

I've created a complete sales metrics dashboard with:

**Features:**
- Key metrics cards showing total revenue, orders, average order value, and conversion rate with percentage changes
- Revenue trend line chart showing daily performance
- Sales by category doughnut chart
- Monthly comparison bar chart
- Top products horizontal bar chart
- Recent transactions table with status indicators
- Period selector for different time ranges
- Responsive design that works on mobile and desktop

**To use:**
Open `index.html` in a browser. The dashboard uses sample data and Chart.js (loaded from CDN) for visualizations. You can replace the sample data in `sample-data.js` with real data from your backend API.

