<!-- Visually hidden utility -->
<style>.sr-only{position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0}</style>

<script>
  // ── Helpers ──────────────────────────────────────────────────────────────
  const fmt = {
    currency: v => '$' + v.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 }),
    percent:  v => v.toFixed(1) + '%',
    number:   v => v.toLocaleString('en-US'),
  };

  function randomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
  }

  function randomFloat(min, max, dp = 1) {
    return parseFloat((Math.random() * (max - min) + min).toFixed(dp));
  }

  // ── Data Generation ───────────────────────────────────────────────────────
  function generateData(days) {
    const now = new Date();
    const labels = [];
    const revenue = [];
    const orders = [];

    for (let i = days - 1; i >= 0; i--) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      labels.push(d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }));

      const base = 8000 + Math.sin(i * 0.4) * 2000;
      revenue.push(Math.round(base + randomInt(-1500, 2500)));
      orders.push(randomInt(40, 120));
    }

    const totalRevenue = revenue.reduce((a, b) => a + b, 0);
    const totalOrders  = orders.reduce((a, b) => a + b, 0);
    const aov = totalRevenue / totalOrders;
    const convRate = randomFloat(2.4, 5.8);

    const categories = [
      { name: 'Electronics', value: randomInt(28, 38) },
      { name: 'Apparel',     value: randomInt(18, 26) },
      { name: 'Home & Garden', value: randomInt(12, 20) },
      { name: 'Sports',     value: randomInt(10, 16) },
      { name: 'Other',      value: randomInt(8, 14) },
    ];

    const transactions = Array.from({ length: 8 }, (_, idx) => {
      const d = new Date(now);
      d.setDate(d.getDate() - randomInt(0, days - 1));
      const statuses = ['completed', 'completed', 'completed', 'pending', 'refunded'];
      return {
        id: '#' + String(100200 + idx + randomInt(0, 800)),
        customer: ['Alice M.','Bob K.','Carol T.','David L.','Eva P.','Frank R.','Grace H.','Henry W.'][idx],
        amount: randomInt(49, 890),
        status: statuses[randomInt(0, statuses.length - 1)],
        date: d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
      };
    });

    const funnel = [
      { name: 'Visitors',       count: 84200 },
      { name: 'Product Views',  count: 31400 },
      { name: 'Add to Cart',    count: 9800  },
      { name: 'Checkout',       count: 4100  },
      { name: 'Purchase',       count: 2950  },
    ];

    // prior-period deltas (simulated)
    const delta = {
      revenue: randomFloat(-8, 18),
      orders:  randomFloat(-5, 15),
      aov:     randomFloat(-4, 10),
      conv:    randomFloat(-1, 2.5),
    };

    return { labels, revenue, orders, totalRevenue, totalOrders, aov, convRate, categories, transactions, funnel, delta };
  }

  // ── Render KPIs ───────────────────────────────────────────────────────────
  function renderKPIs(data) {
    const { totalRevenue, totalOrders, aov, convRate, delta } = data;

    const kpis = [
      { el: 'kpi-revenue', delta: 'kpi-revenue-delta', value: fmt.currency(totalRevenue), change: delta.revenue, suffix: '' },
      { el: 'kpi-orders',  delta: 'kpi-orders-delta',  value: fmt.number(totalOrders),    change: delta.orders,  suffix: '' },
      { el: 'kpi-aov',     delta: 'kpi-aov-delta',     value: fmt.currency(aov),          change: delta.aov,     suffix: '' },
      { el: 'kpi-conv',    delta: 'kpi-conv-delta',    value: fmt.percent(convRate),      change: delta.conv,    suffix: 'pp' },
    ];

    kpis.forEach(({ el, delta: deltaEl, value, change, suffix }) => {
      document.getElementById(el).textContent = value;
      const deltaDiv = document.getElementById(deltaEl);
      const up = change >= 0;
      deltaDiv.className = 'kpi-delta ' + (up ? 'up' : 'down');
      deltaDiv.innerHTML = `<span class="arrow" aria-hidden="true">${up ? '▲' : '▼'}</span>
        <span>${up ? '+' : ''}${change.toFixed(1)}${suffix}% vs prior period</span>`;
    });
  }

  // ── Charts ────────────────────────────────────────────────────────────────
  let revenueChart, categoryChart;

  const CHART_DEFAULTS = {
    color: '#8b90b8',
    font: { family: "'Segoe UI', system-ui, sans-serif", size: 12 },
  };

  Chart.defaults.color = CHART_DEFAULTS.color;
  Chart.defaults.font  = CHART_DEFAULTS.font;

  function buildRevenueChart(data) {
    const ctx = document.getElementById('revenueChart').getContext('2d');

    // Thin the labels if many days
    const step = data.labels.length > 30 ? 7 : data.labels.length > 14 ? 3 : 1;
    const sparseLabels = data.labels.map((l, i) => i % step === 0 ? l : '');

    const gradient = ctx.createLinearGradient(0, 0, 0, 250);
    gradient.addColorStop(0,   'rgba(108,99,255,0.35)');
    gradient.addColorStop(1,   'rgba(108,99,255,0)');

    revenueChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels: sparseLabels,
        datasets: [{
          label: 'Revenue',
          data: data.revenue,
          borderColor: '#6c63ff',
          backgroundColor: gradient,
          borderWidth: 2.5,
          pointRadius: 0,
          pointHoverRadius: 5,
          pointHoverBackgroundColor: '#6c63ff',
          fill: true,
          tension: 0.4,
        }],
      },
      options: {
        responsive: true,
        interaction: { mode: 'index', intersect: false },
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#1a1d27',
            borderColor: '#2e3250',
            borderWidth: 1,
            padding: 12,
            callbacks: {
              label: ctx => ' Revenue: ' + fmt.currency(ctx.parsed.y),
            },
          },
        },
        scales: {
          x: {
            grid: { color: 'rgba(255,255,255,0.04)' },
            ticks: { maxRotation: 0 },
          },
          y: {
            grid: { color: 'rgba(255,255,255,0.06)' },
            ticks: { callback: v => fmt.currency(v) },
          },
        },
      },
    });
  }

  function buildCategoryChart(data) {
    const ctx = document.getElementById('categoryChart').getContext('2d');
    const colors = ['#6c63ff','#00d4aa','#ffb347','#ff6584','#a78bfa'];

    categoryChart = new Chart(ctx, {
      type: 'doughnut',
      data: {
        labels: data.categories.map(c => c.name),
        datasets: [{
          data: data.categories.map(c => c.value),
          backgroundColor: colors,
          borderColor: '#1a1d27',
          borderWidth: 3,
          hoverOffset: 6,
        }],
      },
      options: {
        responsive: true,
        cutout: '68%',
        plugins: {
          legend: {
            position: 'bottom',
            labels: { padding: 14, boxWidth: 12, borderRadius: 2 },
          },
          tooltip: {
            backgroundColor: '#1a1d27',
            borderColor: '#2e3250',
            borderWidth: 1,
            callbacks: {
              label: ctx => ` ${ctx.label}: ${ctx.parsed}%`,
            },
          },
        },
      },
    });
  }

  function updateCharts(data) {
    if (revenueChart) revenueChart.destroy();
    if (categoryChart) categoryChart.destroy();
    buildRevenueChart(data);
    buildCategoryChart(data);
  }

  // ── Transactions Table ────────────────────────────────────────────────────
  function renderTransactions(transactions) {
    const tbody = document.getElementById('transactions-body');
    tbody.innerHTML = transactions.map(t => `
      <tr>
        <td><code style="color:var(--accent);font-size:0.8rem">${t.id}</code></td>
        <td>${t.customer}</td>
        <td style="font-weight:600">${fmt.currency(t.amount)}</td>
        <td><span class="badge badge-${t.status}">${t.status.charAt(0).toUpperCase() + t.status.slice(1)}</span></td>
        <td style="color:var(--text-muted)">${t.date}</td>
      </tr>
    `).join('');
  }

  // ── Funnel ────────────────────────────────────────────────────────────────
  function renderFunnel(funnel) {
    const container = document.getElementById('funnel-steps');
    const max = funnel[0].count;
    const colors = ['#6c63ff','#7c73ff','#00d4aa','#ffb347','#ff6584'];

    container.innerHTML = funnel.map((step, i) => {
      const pct = ((step.count / max) * 100).toFixed(1);
      return `
        <div class="funnel-step">
          <div class="funnel-step-header">
            <span class="funnel-step-name">${step.name}</span>
            <span class="funnel-step-count">${fmt.number(step.count)}</span>
          </div>
          <div class="funnel-bar-bg" role="progressbar" aria-valuenow="${pct}" aria-valuemin="0" aria-valuemax="100" aria-label="${step.name}: ${pct}%">
            <div class="funnel-bar-fill" style="width:${pct}%;background:${colors[i]}"></div>
          </div>
        </div>
      `;
    }).join('');
  }

  // ── Main Render ───────────────────────────────────────────────────────────
  function render(days) {
    const data = generateData(days);
    renderKPIs(data);
    updateCharts(data);
    renderTransactions(data.transactions);
    renderFunnel(data.funnel);
  }

  // ── Event Listeners ───────────────────────────────────────────────────────
  const rangeSelect  = document.getElementById('range-select');
  const refreshBtn   = document.getElementById('refresh-btn');

  rangeSelect.addEventListener('change', () => render(parseInt(rangeSelect.value, 10)));
  refreshBtn.addEventListener('click',   () => render(parseInt(rangeSelect.value, 10)));

  // Init
  render(30);
</script>
</body>
</html>
"}}
