                            }
                        }
                    }
                }
            });
        }

        // 创建产品分布图
        function createProductChart(data) {
            const ctx = document.getElementById('productChart').getContext('2d');
            new Chart(ctx, {
                type: 'doughnut',
                data: {
                    labels: data.productDistribution.map(item => item.name),
                    datasets: [{
                        data: data.productDistribution.map(item => item.value),
                        backgroundColor: [
