                            '#764ba2',
                            '#f093fb',
                            '#4facfe',
                            '#43e97b'
                        ]
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: true,
                    plugins: {
                        legend: {
                            position: 'bottom'
                        }
                    }
                }
            });
        }

        // 填充产品表格
        function populateTable(data) {
            const tbody = document.getElementById('tableBody');
            tbody.innerHTML = data.topProducts.map((product, index) => `
                <tr>
                    <td><strong>${index + 1}</strong></td>
