const PERIODS = {
  week:    { label: '近7天',  days: 7  },
  month:   { label: '近30天', days: 30 },
  quarter: { label: '近90天', days: 90 },
  year:    { label: '近365天',days: 365 },
};

let currentPeriod = 'week';

/* Deterministic pseudo-random seeded by period so refresh
   produces stable numbers for the same period.             */
function seededRand(seed) {
  let s = seed;
  return () => {
    s = (s * 1664525 + 1013904223) & 0xffffffff;
    return (s >>> 0) / 0xffffffff;
  };
}

function generateData(period) {
  const r = seededRand(period.length * 31 + 7);

  const base = { week: 1, month: 4, quarter: 12, year: 50 }[period];

  const kpis = [
    {
      label: '总销售额',
      value: fmt(Math.round((120 + r() * 80) * base * 10000)),
      prefix: '¥',
      change: +((-15 + r() * 30)).toFixed(1),
