      label: '订单数量',
      value: Math.round((300 + r() * 200) * base),
      change: +((-10 + r() * 25)).toFixed(1),
      sub: '同比',
      color: 'green',
      icon: '📦',
    },
    {
      label: '客单价',
      value: fmt(Math.round(800 + r() * 400)),
      prefix: '¥',
      change: +((-8 + r() * 16)).toFixed(1),
      sub: '同比',
      color: 'yellow',
      icon: '🏷️',
    },
    {
      label: '新增客户',
      value: Math.round((40 + r() * 60) * base),
      change: +((-5 + r() * 20)).toFixed(1),
      sub: '同比',
      color: 'cyan',
      icon: '🙋',
    },
    {
      label: '目标完成率',
      value: (65 + r() * 30).toFixed(1) + '%',
      change: +((-6 + r() * 12)).toFixed(1),
      sub: '较上期',
      color: 'purple',
      icon: '🎯',
    },
    {
      label: '退款率',
      value: (1 + r() * 4).toFixed(1) + '%',
      change: +((-2 + r() * 4)).toFixed(1),
      sub: '较上期',
      color: 'red',
      icon: '↩️',
      invertBadge: true,
    },
  ];

  const days = PERIODS[period].days;
  const trendDates = [];
  const trendValues = [];
  const trendValues2 = [];
  const now = new Date();
  for (let i = days - 1; i >= 0; i--) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    trendDates.push(fmtDate(d, days));
    const v = Math.round((5000 + r() * 8000) * (base ** 0.6));
    trendValues.push(v);
    trendValues2.push(Math.round(v * (0.5 + r() * 0.4)));
  }

  const channels = [
    { name: '直销',     color: '#4f6ef7', pct: 10 + r() * 25 },
    { name: '电商平台', color: '#22c55e', pct: 10 + r() * 25 },
    { name: '代理商',   color: '#f59e0b', pct: 10 + r() * 20 },
    { name: '线下门店', color: '#06b6d4', pct:  5 + r() * 15 },
    { name: '其他',     color: '#7c5cbf', pct:  2 + r() * 8  },
  ];
  const total = channels.reduce((s, c) => s + c.pct, 0);
  channels.forEach(c => c.pct = +(c.pct / total * 100).toFixed(1));

  const products = [
    '旗舰产品A', '标准套餐B', '企业版C', '基础版D', '增值服务E', '定制方案F',
  ].map((name, i) => ({
    name,
    value: Math.round((200 + r() * 600) * base * 10000),
    color: ['#4f6ef7','#22c55e','#f59e0b','#06b6d4','#7c5cbf','#ef4444'][i],
  })).sort((a, b) => b.value - a.value);

  const salespeople = [
    '张伟', '李芳', '王磊', '刘洋', '陈静', '赵敏', '孙强', '周涛',
  ].map((name, i) => {
    const sale = Math.round((80 + r() * 120) * base * 10000);
    const target = Math.round(sale * (0.8 + r() * 0.5));
    const spark = Array.from({length: 7}, () => Math.round(r() * 100));
    return { name, sale, target, rate: +(sale / target * 100).toFixed(1), spark };
  }).sort((a, b) => b.rate - a.rate);

  return { kpis, trendDates, trendValues, trendValues2, channels, products, salespeople };
}

/* =========================================================
   HELPERS
   ========================================================= */

function fmt(n) {
  if (n >= 100000000) return (n / 100000000).toFixed(2) + '亿';
  if (n >= 10000)     return (n / 10000).toFixed(1) + '万';
  return n.toLocaleString();
}

function fmtDate(d, days) {
  if (days <= 7)  return `${d.getMonth()+1}/${d.getDate()}`;
  if (days <= 31) return `${d.getMonth()+1}/${d.getDate()}`;
  if (days <= 90) return `${d.getMonth()+1}月${Math.ceil(d.getDate()/7)}周`;
  return `${d.getMonth()+1}月`;
}

function badge(change, invert = false) {
  const positive = invert ? change < 0 : change > 0;
  const cls = change === 0 ? 'flat' : (positive ? 'up' : 'down');
  const arrow = change === 0 ? '—' : (positive ? '▲' : '▼');
  return `<span class="badge ${cls}">${arrow} ${Math.abs(change)}%</span>`;
}

/* =========================================================
   RENDER KPI CARDS
   ========================================================= */

function renderKPIs(kpis) {
  const grid = document.getElementById('kpiGrid');
  grid.innerHTML = kpis.map(k => `
    <div class="kpi-card ${k.color}">
      <div class="kpi-label">${k.icon} ${k.label}</div>
      <div class="kpi-value">${k.prefix || ''}${k.value}</div>
      <div class="kpi-footer">
        ${badge(k.change, k.invertBadge)}
        <span class="kpi-sub">${k.sub}上期</span>
      </div>
    </div>
  `).join('');
}

/* =========================================================
   TREND LINE CHART  (vanilla canvas)
   ========================================================= */

function renderTrendChart(dates, values, values2) {
  const canvas = document.getElementById('trendChart');
  const wrap   = canvas.parentElement;
  const W = wrap.clientWidth  || 600;
  const H = wrap.clientHeight || 200;
  canvas.width  = W;
  canvas.height = H;

  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, W, H);

  const PAD = { top: 16, right: 20, bottom: 36, left: 52 };
  const cW = W - PAD.left - PAD.right;
  const cH = H - PAD.top  - PAD.bottom;

  const allVals = [...values, ...values2];
  const minV = 0;
  const maxV = Math.max(...allVals) * 1.15;

  const xScale = i => PAD.left + (i / (values.length - 1)) * cW;
  const yScale = v => PAD.top  + cH - ((v - minV) / (maxV - minV)) * cH;

  /* Grid lines */
  ctx.strokeStyle = 'rgba(255,255,255,.06)';
  ctx.lineWidth = 1;
  for (let i = 0; i <= 4; i++) {
    const y = PAD.top + (i / 4) * cH;
    ctx.beginPath(); ctx.moveTo(PAD.left, y); ctx.lineTo(PAD.left + cW, y); ctx.stroke();

    const val = maxV - (i / 4) * maxV;
    ctx.fillStyle = 'rgba(255,255,255,.3)';
    ctx.font = '11px sans-serif';
    ctx.textAlign = 'right';
    ctx.fillText(fmt(Math.round(val)), PAD.left - 6, y + 4);
  }

  function drawLine(vals, color, fill) {
    /* Gradient fill */
    const grad = ctx.createLinearGradient(0, PAD.top, 0, PAD.top + cH);
    grad.addColorStop(0, fill);
    grad.addColorStop(1, 'transparent');

    ctx.beginPath();
    vals.forEach((v, i) => {
      const x = xScale(i), y = yScale(v);
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    });
    const path = new Path2D(ctx.currentPath);  // save line path
    ctx.strokeStyle = color;
    ctx.lineWidth = 2.5;
    ctx.lineJoin = 'round';
    ctx.stroke();

    /* Area */
    ctx.lineTo(xScale(vals.length - 1), PAD.top + cH);
    ctx.lineTo(PAD.left, PAD.top + cH);
    ctx.closePath();
    ctx.fillStyle = grad;
    ctx.fill();
  }

  /* Draw area by continuing path */
  function drawSeries(vals, color, fillColor) {
    const grad = ctx.createLinearGradient(0, PAD.top, 0, PAD.top + cH);
    grad.addColorStop(0, fillColor);
    grad.addColorStop(1, 'rgba(0,0,0,0)');

    ctx.save();
    ctx.beginPath();
    vals.forEach((v, i) => {
      const x = xScale(i), y = yScale(v);
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    });
    ctx.strokeStyle = color;
    ctx.lineWidth = 2.5;
    ctx.lineJoin = 'round';
    ctx.stroke();

    ctx.lineTo(xScale(vals.length - 1), PAD.top + cH);
    ctx.lineTo(xScale(0), PAD.top + cH);
    ctx.closePath();
    ctx.fillStyle = grad;
    ctx.fill();
    ctx.restore();
  }

  drawSeries(values2, 'rgba(124,92,191,.7)', 'rgba(124,92,191,.18)');
  drawSeries(values,  '#4f6ef7',             'rgba(79,110,247,.25)');

  /* Dots */
  values.forEach((v, i) => {
    ctx.beginPath();
    ctx.arc(xScale(i), yScale(v), 3, 0, Math.PI * 2);
    ctx.fillStyle = '#4f6ef7';
    ctx.fill();
  });

  /* X axis labels */
  ctx.fillStyle = 'rgba(255,255,255,.35)';
  ctx.font = '11px sans-serif';
  ctx.textAlign = 'center';

  const step = Math.max(1, Math.floor(dates.length / 8));
  dates.forEach((d, i) => {
    if (i % step === 0 || i === dates.length - 1) {
      ctx.fillText(d, xScale(i), H - 10);
    }
  });

  /* Legend */
  const legends = [
    { color: '#4f6ef7', label: '本期销售额' },
    { color: 'rgba(124,92,191,.7)', label: '上期对比' },
  ];
  legends.forEach((l, i) => {
    const lx = PAD.left + i * 120;
    const ly = H - PAD.bottom + 20;
    ctx.fillStyle = l.color;
    ctx.fillRect(lx, ly, 14, 3);
    ctx.fillStyle = 'rgba(255,255,255,.5)';
    ctx.font = '11px sans-serif';
    ctx.textAlign = 'left';
    ctx.fillText(l.label, lx + 18, ly + 4);
  });

  /* Interactive tooltip */
  canvas._data = { dates, values, values2, xScale, yScale, PAD };
}

/* Canvas tooltip */
document.getElementById('trendChart').addEventListener('mousemove', function(e) {
  if (!this._data) return;
  const { dates, values, values2, xScale, yScale } = this._data;
  const rect = this.getBoundingClientRect();
  const mx = e.clientX - rect.left;

  let closest = 0, minDist = Infinity;
  values.forEach((_, i) => {
    const d = Math.abs(xScale(i) - mx);
    if (d < minDist) { minDist = d; closest = i; }
  });

  if (minDist < 30) {
    const tip = document.getElementById('tooltip');
    tip.innerHTML = `<b>${dates[closest]}</b><br>本期：¥${fmt(values[closest])}<br>上期：¥${fmt(values2[closest])}`;
    tip.style.opacity = '1';
    tip.style.left = (e.clientX + 14) + 'px';
    tip.style.top  = (e.clientY - 10) + 'px';
  }
});

document.getElementById('trendChart').addEventListener('mouseleave', () => {
  document.getElementById('tooltip').style.opacity = '0';
});

/* =========================================================
   DONUT CHART (SVG)
   ========================================================= */

function renderDonut(channels) {
  const svg = document.getElementById('donutSvg');
  const R = 80, r = 52, cx = 80, cy = 80;
  let angle = -Math.PI / 2;
  let paths = '';

  channels.forEach(c => {
    const sweep = (c.pct / 100) * Math.PI * 2;
    const x1 = cx + R * Math.cos(angle);
    const y1 = cy + R * Math.sin(angle);
    const x2 = cx + R * Math.cos(angle + sweep);
    const y2 = cy + R * Math.sin(angle + sweep);
    const ix1 = cx + r * Math.cos(angle);
    const iy1 = cy + r * Math.sin(angle);
    const ix2 = cx + r * Math.cos(angle + sweep);
    const iy2 = cy + r * Math.sin(angle + sweep);
    const large = sweep > Math.PI ? 1 : 0;

    paths += `<path d="M ${x1} ${y1} A ${R} ${R} 0 ${large} 1 ${x2} ${y2}
              L ${ix2} ${iy2} A ${r} ${r} 0 ${large} 0 ${ix1} ${iy1} Z"
              fill="${c.color}" opacity=".85"
              data-name="${c.name}" data-pct="${c.pct}%"
              class="donut-seg" />`;
    angle += sweep;
  });

  svg.innerHTML = paths + `
    <text x="${cx}" y="${cy - 6}" text-anchor="middle" class="donut-center-label">
      ${channels.length}
    </text>
    <text x="${cx}" y="${cy + 14}" text-anchor="middle" class="donut-center-sub">
      渠道
    </text>`;

  /* Legend */
  const legend = document.getElementById('donutLegend');
  legend.innerHTML = channels.map(c => `
    <div class="legend-item">
      <div class="legend-left">
        <div class="legend-dot" style="background:${c.color}"></div>
        ${c.name}
      </div>
      <b>${c.pct}%</b>
    </div>
  `).join('');

  /* Tooltip on segments */
  svg.querySelectorAll('.donut-seg').forEach(seg => {
    seg.addEventListener('mouseenter', e => {
      const tip = document.getElementById('tooltip');
      tip.innerHTML = `${seg.dataset.name}：${seg.dataset.pct}`;
      tip.style.opacity = '1';
    });
    seg.addEventListener('mousemove', e => {
      const tip = document.getElementById('tooltip');
      tip.style.left = (e.clientX + 14) + 'px';
      tip.style.top  = (e.clientY - 10) + 'px';
    });
    seg.addEventListener('mouseleave', () => {
      document.getElementById('tooltip').style.opacity = '0';
    });
    seg.style.cursor = 'pointer';
  });
}

/* =========================================================
   PRODUCT BAR CHART
   ========================================================= */

function renderProductBar(products) {
  const max = products[0].value;
  document.getElementById('productBar').innerHTML = products.map(p => `
    <div class="bar-row">
      <div class="bar-label">${p.name}</div>
      <div class="bar-track">
        <div class="bar-fill" style="width:0%;background:${p.color}"
             data-target="${(p.value/max*100).toFixed(1)}"></div>
      </div>
      <div class="bar-val">¥${fmt(p.value)}</div>
    </div>
  `).join('');

  /* Animate bars */
  requestAnimationFrame(() => {
    document.querySelectorAll('.bar-fill').forEach(el => {
      el.style.width = el.dataset.target + '%';
    });
  });
}

/* =========================================================
   SALES TABLE
   ========================================================= */

function renderSalesTable(people) {
  document.getElementById('salesTable').innerHTML = people.map((p, i) => {
    const rankClass = i === 0 ? 'rank-1' : i === 1 ? 'rank-2' : i === 2 ? 'rank-3' : 'rank-n';
    const rateColor = p.rate >= 100 ? 'var(--green)' : p.rate >= 80 ? 'var(--yellow)' : 'var(--red)';
    const sparkSvg = miniSparkline(p.spark);
    return `
      <tr>
        <td><span class="rank ${rankClass}">${i+1}</span></td>
        <td>${p.name}</td>
        <td>¥${fmt(p.sale)}</td>
        <td>
          <div style="color:${rateColor};font-weight:600">${p.rate}%</div>
          <div class="progress-track progress-cell">
            <div class="progress-fill" style="width:${Math.min(p.rate,100)}%;background:${rateColor}"></div>
          </div>
        </td>
        <td>${sparkSvg}</td>
      </tr>
    `;
  }).join('');
}

function miniSparkline(data) {
  const w = 60, h = 24;
  const max = Math.max(...data), min = Math.min(...data);
  const range = max - min || 1;
  const pts = data.map((v, i) => {
    const x = (i / (data.length - 1)) * w;
    const y = h - ((v - min) / range) * (h - 4) - 2;
    return `${x},${y}`;
  }).join(' ');
  const trend = data[data.length - 1] >= data[0];
  const color = trend ? 'var(--green)' : 'var(--red)';
  return `<svg width="${w}" height="${h}" class="spark">
    <polyline points="${pts}" fill="none" stroke="${color}" stroke-width="1.5" stroke-linejoin="round"/>
  </svg>`;
}

/* =========================================================
   MAIN RENDER
   ========================================================= */

function render(period) {
  const data = generateData(period);
  renderKPIs(data.kpis);
  renderTrendChart(data.trendDates, data.trendValues, data.trendValues2);
  renderDonut(data.channels);
  renderProductBar(data.products);
  renderSalesTable(data.salespeople);
  document.getElementById('lastUpdate').textContent =
    '数据更新时间：' + new Date().toLocaleString('zh-CN');
  document.getElementById('trendPeriodLabel').textContent = PERIODS[period].label;
}

/* =========================================================
   EVENTS
   ========================================================= */

document.querySelectorAll('.period-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    document.querySelectorAll('.period-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    currentPeriod = btn.dataset.period;
    render(currentPeriod);
  });
});

document.getElementById('refreshBtn').addEventListener('click', () => {
  const icon = document.querySelector('#refreshBtn svg');
  icon.style.animation = 'spin .6s linear';
  setTimeout(() => icon.style.animation = '', 600);
  render(currentPeriod);
});

window.addEventListener('resize', () => {
  const data = generateData(currentPeriod);
  renderTrendChart(data.trendDates, data.trendValues, data.trendValues2);
});

/* Spin animation */
const style = document.createElement('style');
style.textContent = `@keyframes spin { to { transform: rotate(360deg); } }`;
document.head.appendChild(style);

/* =========================================================
   INIT
   ========================================================= */
render('week');
</script>
</body>
